+    let mut script = String::new();
+    script.push_str("#!/usr/bin/env sh\n");
+    script.push_str("set -eu\n");
+    for (key, value) in &harness.env {
+        script.push_str("export ");
+        script.push_str(key);
+        script.push('=');
+        script.push_str(&sh_escape(value));
